#include <stdio.h>
#include <string.h>
#include <stdlib.h>

// Compute prefix function (KMP) for a character array
void computePrefix(const char *str, int n, int *pi) {
    pi[0] = 0;
    for (int i = 1; i < n; ++i) {
        int j = pi[i - 1];
        while (j > 0 && str[i] != str[j])
            j = pi[j - 1];
        if (str[i] == str[j])
            ++j;
        pi[i] = j;
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[100005];
        scanf("%s", s);
        int n = strlen(s);
        // reverse of s
        char rev[100005];
        for (int i = 0; i < n; ++i) rev[i] = s[n - 1 - i];
        rev[n] = '\0';
        // build temporary string s#rev
        char tmp[200010];
        sprintf(tmp, "%s#%s", s, rev);
        int m = strlen(tmp);
        int *pi = (int *)malloc(m * sizeof(int));
        computePrefix(tmp, m, pi);
        int L = pi[m - 1]; // length of longest palindromic prefix
        // output characters to add
        for (int i = 0; i < n - L; ++i) putchar(rev[i]);
        printf("%s\n", s);
        free(pi);
    }
    return 0;
}

