#include <bits/stdc++.h>
using namespace std;

vector<int> prefixFunction(const string &s) {
    int n = s.size();
    vector<int> pi(n);
    for (int i = 1; i < n; ++i) {
        int j = pi[i - 1];
        while (j > 0 && s[i] != s[j]) j = pi[j - 1];
        if (s[i] == s[j]) ++j;
        pi[i] = j;
    }
    return pi;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        string s;
        cin >> s;
        string rev = s;
        reverse(rev.begin(), rev.end());
        string tmp = s + '#' + rev;
        vector<int> pi = prefixFunction(tmp);
        int L = pi.back();
        string add = rev.substr(0, s.size() - L);
        cout << add << s << '\n';
    }
    return 0;
}

