const T = parseInt(lines[idx++], 10);
let output = [];
function prefixFunction(str) {
  const n = str.length;
  const pi = new Array(n).fill(0);
  for (let i = 1; i < n; i++) {
    let j = pi[i - 1];
    while (j > 0 && str[i] !== str[j]) j = pi[j - 1];
    if (str[i] === str[j]) j++;
    pi[i] = j;
  }
  return pi;
}
for (let caseNum = 0; caseNum < T; caseNum++) {
  const s = lines[idx++] || '';
  const rev = s.split('').reverse().join('');
  const tmp = s + '#' + rev;
  const pi = prefixFunction(tmp);
  const L = pi[pi.length - 1];
  const add = rev.substring(0, s.length - L);
  output.push(add + s);
}
